const axios = require('axios');
const fs = require('fs');
const path = require('path');

const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;
const PREMBLY_SANDBOX_URL = 'https://api.prembly.com/api/v1/checker-widget/sdk/sessions/';
const OUTPUT_LOG_PATH = '/home/user/app/output.log';

async function pollPremblySessions() {
  try {
    if (!PREMBLY_API_KEY) {
      throw new Error('PREMBLY_API_KEY environment variable is not set');
    }

    console.log('Fetching Prembly SDK sessions...');

    const response = await axios.get(PREMBLY_SANDBOX_URL, {
      headers: {
        'x-api-key': PREMBLY_API_KEY,
        'Content-Type': 'application/json'
      }
    });

    const data = response.data;

    // Count total sessions from the response
    // The response structure may vary, so we'll handle different possible structures
    let totalSessions = 0;

    if (Array.isArray(data)) {
      totalSessions = data.length;
    } else if (data.data && Array.isArray(data.data)) {
      totalSessions = data.data.length;
    } else if (data.sessions && Array.isArray(data.sessions)) {
      totalSessions = data.sessions.length;
    } else if (data.results && Array.isArray(data.results)) {
      totalSessions = data.results.length;
    } else if (data.total !== undefined) {
      totalSessions = data.total;
    } else if (data.count !== undefined) {
      totalSessions = data.count;
    } else {
      console.log('Response data:', JSON.stringify(data, null, 2));
      totalSessions = 0;
    }

    const output = `Total sessions: ${totalSessions}`;

    // Write to output log file
    fs.writeFileSync(OUTPUT_LOG_PATH, output);

    console.log(`Successfully wrote to ${OUTPUT_LOG_PATH}`);
    console.log(output);

    return totalSessions;
  } catch (error) {
    const errorMessage = `Error fetching Prembly sessions: ${error.message}`;
    console.error(errorMessage);

    if (error.response) {
      console.error('Response status:', error.response.status);
      console.error('Response data:', JSON.stringify(error.response.data, null, 2));
    }

    // Write error to log file
    fs.writeFileSync(OUTPUT_LOG_PATH, errorMessage);

    throw error;
  }
}

// Run the polling function
pollPremblySessions()
  .then(count => {
    console.log(`Polling completed. Found ${count} sessions.`);
  })
  .catch(error => {
    console.error('Polling failed:', error.message);
    process.exit(1);
  });

